1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const FIRST_INSURANCE_MULTIPLIER = 1.1;
6	const CURSED_MULTIPLIER = 1.5;
7	const HIGH_ENCHANTMENT_MULTIPLIER = 1.3;
8	const ADMIN_FEE = 5;
9	
10	const BASE_PRICE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	};
16	
17	function itemModifierMultiplier(item: Item): number {
18	  const cursed = item.cursed ? CURSED_MULTIPLIER : 1;
19	  const highEnchantment =
20	    (item.enchantment ?? 0) >= 5 ? HIGH_ENCHANTMENT_MULTIPLIER : 1;
21	  return cursed * highEnchantment;
22	}
23	
24	// MHPCO always rounds the euro value of a discounted/loaded price upward
25	// (in the office's favour). The toFixed(10) step strips IEEE-754 drift so
26	// values that are mathematically integer (e.g. 100 × 1.10 = 110) don't get
27	// bumped up a euro by a 110.00000000000001 representation.
28	function ceilInMhpcoFavor(value: number): number {
29	  return Math.ceil(Number(value.toFixed(10)));
30	}
31	
32	export function runScenario(scenario: unknown): unknown {
33	  const { steps } = scenario as Scenario;
34	  const item = steps[0].items[0];
35	  const itemPrice = BASE_PRICE[item.type] * itemModifierMultiplier(item);
36	  const premium = ceilInMhpcoFavor(itemPrice * FIRST_INSURANCE_MULTIPLIER) + ADMIN_FEE;
37	  return { results: [{ premium }] };
38	}
