export function runScenario(scenario: unknown): unknown {
  const { customer, steps } = scenario as Scenario;
  const item = steps[0].items[0];
  const itemPrice = BASE_PRICE[item.type] * itemModifierMultiplier(item);
  const loyaltyMultiplier =
    customer.yearsWithMHPCO >= 2 ? LOYALTY_MULTIPLIER : 1;
  const premium =
    ceilInMhpcoFavor(itemPrice * loyaltyMultiplier * FIRST_INSURANCE_MULTIPLIER) +
    ADMIN_FEE;
  return { results: [{ premium }] };
}
